import React from 'react'
import styled from 'styled-components'
import Navbar from '../components/Navbar'
import Header from '../components/Header'
import Banner from '../components/Banner'
import TrendingSection from '../components/TrendingSection'
import PopularDesignerSection from '../components/PopularDesignerSection'
import Footer from '../components/Footer'
import AccountForm from '../components/LoginLogout'
import {accountSelector} from '../redux/accountSlice'
import {useSelector} from 'react-redux'


const BlendBackground = styled.div `
background-color:rgba(0, 0, 0, 0.7);
width:100vw;
height:100vh;
position:fixed;
`

export default function Main () {
	const account = useSelector(accountSelector)

	return (
		<>
			{account.isLoginFormOpen ? <BlendBackground /> : null}
			<AccountForm />
			<Header />
			<Navbar >
			<Banner />
			</Navbar>

			<TrendingSection />
			<PopularDesignerSection />
			<Footer />
		</>

	)
}
